const PROCESSING_FEE = 5;

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const basePremiumFor = (item: Item): number => ITEM_BASE_PREMIUM[item.type];

const quote = (step: QuoteStep): QuoteResult => {
  const itemsBaseTotal = step.items.reduce(
    (sum, item) => sum + basePremiumFor(item),
    0,
  );
  return { premium: itemsBaseTotal + PROCESSING_FEE };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") return quote(step);
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};
